 16→func verbose() bool {
 17→	// Check both VERBOSE and SANDCASTLE_VERBOSE
 18→	v := strings.ToLower(os.Getenv("VERBOSE"))
 19→	if v == "" {
 20→		v = strings.ToLower(os.Getenv("SANDCASTLE_VERBOSE"))
 21→	}
 22→	return v == "1" || v == "true"
 23→}
 24→
 25→func logVerbose(format string, args ...any) {
 26→	if verbose() {
 27→		fmt.Fprintf(os.Stderr, "\033[2m"+format+"\033[0m\n", args...)
 28→	}
 29→}
