 31→type Client struct {
 32→	BaseURL     string
 33→	Token       string
 34→	ServerAlias string
 35→	HTTPClient  *http.Client
 36→}
 37→
 38→func newHTTPClient(insecure bool) *http.Client {
 39→	if insecure {
 40→		return &http.Client{
 41→			Transport: &http.Transport{
 42→				TLSClientConfig: &tls.Config{InsecureSkipVerify: true},
 43→			},
 44→		}
 45→	}
 46→	return &http.Client{}
 47→}
 48→
 49→func NewClient() (*Client, error) {
 50→	cfg, err := config.Load()
 51→	if err != nil {
 52→		return nil, err
 53→	}
 54→
 55→	// SANDCASTLE_HOST overrides the active server — accepts a server alias or URL.
 56→	if host := os.Getenv("SANDCASTLE_HOST"); host != "" {
 57→		// 1. Alias match
 58→		if srv, ok := cfg.Servers[host]; ok {
 59→			logVerbose("server (SANDCASTLE_HOST alias): %s (%s)", host, srv.URL)
 60→			return &Client{
 61→				BaseURL:     srv.URL,
 62→				Token:       srv.Token,
 63→				ServerAlias: host,
 64→				HTTPClient:  newHTTPClient(srv.Insecure),
 65→			}, nil
 66→		}
 67→		// 2. URL match — reuse stored token for that server
 68→		normalized := strings.TrimRight(host, "/")
 69→		for alias, srv := range cfg.Servers {
 70→			if strings.TrimRight(srv.URL, "/") == normalized {
 71→				logVerbose("server (SANDCASTLE_HOST url): %s (%s)", alias, normalized)
 72→				return &Client{
 73→					BaseURL:     normalized,
 74→					Token:       srv.Token,
 75→					ServerAlias: alias,
 76→					HTTPClient:  newHTTPClient(srv.Insecure),
 77→				}, nil
 78→			}
 79→		}
 80→		// 3. Unknown URL — use without auth
 81→		logVerbose("server (SANDCASTLE_HOST, unauthenticated): %s", normalized)
 82→		return &Client{
 83→			BaseURL:    normalized,
 84→			HTTPClient: newHTTPClient(false),
 85→		}, nil
 86→	}
 87→
 88→	srv, err := cfg.CurrentServerConfig()
 89→	if err != nil {
 90→		return nil, err
 91→	}
 92→	logVerbose("server: %s (%s)", cfg.CurrentServer, srv.URL)
 93→	return &Client{
 94→		BaseURL:     srv.URL,
 95→		Token:       srv.Token,
 96→		ServerAlias: cfg.CurrentServer,
 97→		HTTPClient:  newHTTPClient(srv.Insecure),
 98→	}, nil
 99→}
